// This is a React function component
import React, { useState, useReducer } from 'react';

function Counter(props) {
  const [counters, setCounters] = useState([{
    id: 1,
    value: 5
  }]);

  const [countersValues, dispatch] = useReducer((state, action) => {
    if (action.type === 'UPDATE_COUNTER') {
      return state.map(counter => {
        if (counter.id === action.id) {
          return { ...counter, value: action.value }
        }
        return counter;
      });
    }
    return state;
  }, []);

  const updateCounter = (id, value) => {
    dispatch({ type: 'UPDATE_COUNTER', id, value });
  }

  return (
    <div>
      {countersValues.map((counter, index) => (
        <p key={index}>{counter.value}</p>
      ))}
      <button onClick={() => updateCounter(1, 10)}>Update Counter 1</button>
    </div>
  );
}

export default Counter;

