// This is a React function component
import React, { useState, useReducer } from 'react';

def Counter(props):
  counters, setCounters = useState([{'id': 1, 'value': 5}])

  counters_values, dispatch = useReducer(
    (state, action):
      if action['type'] == 'UPDATE_COUNTER':
        return [{'id': counter['id'], 'value': counter['value']} for counter in state if counter['id'] != action['id']] +
               [{'id': action['id'], 'value': action['value']}]
      return state,
    [],
  )

  def update_counter(id, value):
    dispatch({'type': 'UPDATE_COUNTER', 'id': id, 'value': value})

  return React.createElement(
    'div', null,
    React.createElement(
      'p', {key: 0}, counters_values[0]['value']
    ),
    React.createElement(
      'p', {key: 1}, counters_values[1]['value']
    ),
    React.createElement(
      'button', {onClick: lambda: update_counter(1, 10)},
      'Update Counter 1'
    )
  )

export default Counter
